mapper.select:
        SELECT DISTINCT a.user_b_id FROM app_clean_price_detail as a
	       LEFT JOIN app_b_user as b ON a.user_b_id = b.id
	       WHERE  clean_type = #{cleanType} AND a.state = 1 AND b.city = #{cityCode}

SELECT a.* FROM app_clean_price_detail a
  WHERE  user_b_id = #{userid}
  AND preferential_price = (SELECT MIN(b.preferential_price)FROM app_clean_price_detail b WHERE  b.user_b_id = #{userid}) LIMIT 0,1
